#include <iostream>
#include <list>
#include <string>

struct Player {
    std::string name;
    int initiative;
    int health;

    void display() const {
        std::cout << name << " (Init: " << initiative << ", HP: " << health << ")" << std::endl;
    }
};

int main() {
    std::cout << "=== std::list — Turn-Order Queues ===" << std::endl;

    // 1. Creating a list
    std::cout << "\n--- Creating lists ---" << std::endl;
    std::list<int> numbers = {10, 20, 30, 40, 50};
    std::list<std::string> names = {"Hero", "Aragorn", "Gandalf"};

    // 2. Adding elements
    std::cout << "\n--- Adding elements ---" << std::endl;
    numbers.push_front(5);   // Add to front
    numbers.push_back(60);   // Add to back

    std::cout << "After push_front/push_back: ";
    for (int n : numbers) {
        std::cout << n << " ";
    }
    std::cout << std::endl;

    // 3. Inserting in the middle
    std::cout << "\n--- Inserting in the middle ---" << std::endl;
    auto it = numbers.begin();
    std::advance(it, 3);  // Move to position 3
    numbers.insert(it, 25);  // Insert 25 at position 3

    for (int n : numbers) {
        std::cout << n << " ";
    }
    std::cout << std::endl;

    // 4. Removing elements
    std::cout << "\n--- Removing elements ---" << std::endl;
    numbers.pop_front();  // Remove first
    numbers.pop_back();   // Remove last

    std::cout << "After pop_front/pop_back: ";
    for (int n : numbers) {
        std::cout << n << " ";
    }
    std::cout << std::endl;

    // 5. Removing specific values
    std::cout << "\n--- Removing specific values ---" << std::endl;
    numbers.remove(30);  // Remove all 30s

    std::cout << "After remove(30): ";
    for (int n : numbers) {
        std::cout << n << " ";
    }
    std::cout << std::endl;

    // 6. Game use: turn order
    std::cout << "\n--- Turn Order (list of Players) ---" << std::endl;
    std::list<Player> turnOrder;

    turnOrder.push_back({"Hero", 15, 100});
    turnOrder.push_back({"Goblin", 10, 30});
    turnOrder.push_back({"Orc", 12, 50});
    turnOrder.push_back({"Boss", 20, 150});

    // Sort by initiative (custom compare)
    turnOrder.sort([](const Player& a, const Player& b) {
        return a.initiative > b.initiative;  // Higher initiative first
    });

    std::cout << "Turn Order (highest initiative first):" << std::endl;
    for (const Player& p : turnOrder) {
        std::cout << "  ";
        p.display();
    }

    // 7. Iterators
    std::cout << "\n--- Iterators ---" << std::endl;
    std::list<int> scores = {1, 2, 3, 4, 5};

    std::cout << "Forward: ";
    for (auto it2 = scores.begin(); it2 != scores.end(); ++it2) {
        std::cout << *it2 << " ";
    }
    std::cout << std::endl;

    std::cout << "Backward: ";
    for (auto it2 = scores.rbegin(); it2 != scores.rend(); ++it2) {
        std::cout << *it2 << " ";
    }
    std::cout << std::endl;

    std::cout << "\n--- std::list vs std::vector ---" << std::endl;
    std::cout << "std::list: fast insertion/removal anywhere" << std::endl;
    std::cout << "std::vector: fast random access" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <list>

int main() {
    std::list<int> list = {1, 2, 3, 4, 5};

    // Trying to access by index (ERROR!)
    std::cout << list[2] << std::endl;

    return 0;
}

phase2.explanation:
`std::list` does NOT have `operator[]`! It's a linked list, not an array.

**The fix:**
```cpp
// Use iterators to access elements
auto it = list.begin();
std::advance(it, 2);
std::cout << *it << std::endl;
```

**Or use range-based loops:**
```cpp
for (int value : list) {
    std::cout << value << " ";
}
```

**PlusPlus-chan says:**
"`std::list` is not an array. It doesn't have random access. Use iterators."

