#include <iostream>
#include <list>
#include <string>

int main() {
    std::list<std::string> questLog = {
        "Kill 5 goblins",
        "Find the treasure",
        "Rescue the princess"
    };

    std::cout << "Initial quests:" << std::endl;
    int count = 1;
    for (const std::string& q : questLog) {
        std::cout << count++ << ". " << q << std::endl;
    }

    questLog.push_front("Defeat the dragon");
    questLog.push_back("Return to town");

    auto it = questLog.begin();
    std::advance(it, 2);
    questLog.insert(it, "Collect the key");

    questLog.pop_front();
    questLog.pop_back();

    std::cout << "\nFinal quests:" << std::endl;
    count = 1;
    for (const std::string& q : questLog) {
        std::cout << count++ << ". " << q << std::endl;
    }

    return 0;
}
